record.field:
for rec in records:
    values = {}

    if not rec.x_intake_reference:
        values['x_intake_reference'] = env['ir.sequence'].next_by_code('x_hr.pool') or 'MCEP-HR-F1-0001'

    if not rec.x_name:
        arabic_parts = [part for part in [rec.x_first_name_ar, rec.x_middle_names_ar, rec.x_surname_ar] if part]
        english_parts = [part for part in [rec.x_first_name_en, rec.x_middle_names_en, rec.x_surname_en] if part]
        display_parts = arabic_parts or english_parts
        if display_parts:
            values['x_name'] = ' '.join(display_parts).strip()

    if values:
        rec.sudo().write(values)
